import asyncio, datetime
from fastapi import FastAPI
from fastapi.responses import JSONResponse

app = FastAPI()

# In-memory store (use PostgreSQL in production)
_requests: dict[str, ApprovalRequest] = {}
_events:   dict[str, asyncio.Event]   = {}

def store_request(req: ApprovalRequest) -> None:
    _requests[req.request_id] = req
    _events[req.request_id]   = asyncio.Event()

@app.get("/approvals/{request_id}")
async def get_approval(request_id: str):
    req = _requests.get(request_id)
    if not req:
        return JSONResponse({"error": "not found"}, status_code=404)
    return JSONResponse({
        "request_id":    req.request_id,
        "tool_name":     req.tool_name,
        "action_summary": req.action_summary,
        "action_detail": req.action_detail,
        "risk_level":    req.risk_level,
        "tool_input":    req.tool_input,
        "task_context":  req.task_description,
        "status":        req.status,
        "assigned_to":   req.assigned_to,
        "approvals":     req.approvals,
        "requires_n":    req.requires_n,
        "expires_at":    req.expires_at,
        "created_at":    req.created_at,
    })

@app.post("/approvals/{request_id}/approve")
async def approve(request_id: str, reviewer_id: str, note: str = ""):
    req = _requests.get(request_id)
    if not req:
        return JSONResponse({"error": "not found"}, status_code=404)
    if req.status not in (ApprovalStatus.PENDING, ApprovalStatus.ASSIGNED):
        return JSONResponse({"error": f"cannot approve: status is {req.status}"}, status_code=400)
    if reviewer_id in req.approvals:
        return JSONResponse({"error": "reviewer already approved"}, status_code=400)

    req.approvals.append(reviewer_id)
    req.resolution_note = note

    if req.fully_approved:
        req.status      = ApprovalStatus.APPROVED
        req.resolved_at = datetime.datetime.utcnow().isoformat() + "Z"
        _events[request_id].set()

    return JSONResponse({"status": req.status, "approvals": req.approvals, "requires_n": req.requires_n})

@app.post("/approvals/{request_id}/deny")
async def deny(request_id: str, reviewer_id: str, reason: str = ""):
    req = _requests.get(request_id)
    if not req:
        return JSONResponse({"error": "not found"}, status_code=404)
    if req.status not in (ApprovalStatus.PENDING, ApprovalStatus.ASSIGNED):
        return JSONResponse({"error": f"cannot deny: status is {req.status}"}, status_code=400)

    req.status      = ApprovalStatus.DENIED
    req.deny_reason = reason
    req.resolved_at = datetime.datetime.utcnow().isoformat() + "Z"
    _events[request_id].set()
    return JSONResponse({"status": "denied"})

async def wait_for_approval(request_id: str, timeout: float) -> ApprovalStatus:
    """Block until the request is resolved or the SLA expires."""
    try:
        await asyncio.wait_for(_events[request_id].wait(), timeout=timeout)
        return _requests[request_id].status
    except asyncio.TimeoutError:
        req = _requests[request_id]
        req.status = ApprovalStatus.EXPIRED
        return ApprovalStatus.EXPIRED

import difflib, json

def build_action_summary(tool_name: str, tool_input: dict) -> str:
    """One-line summary suitable for a notification subject line."""
    templates = {
        "delete_records":  "Delete {count} records from '{table}'",
        "send_email":      "Send email to {to} — {subject}",
        "deploy_service":  "Deploy {service} to {environment}",
        "exec_shell":      "Run: {command}",
        "write_config":    "Overwrite config '{path}'",
        "drop_table":      "DROP TABLE {table_name}",
    }
    tmpl = templates.get(tool_name, f"Execute {tool_name}")
    try:
        return tmpl.format(**tool_input)
    except KeyError:
        return f"{tool_name}({json.dumps(tool_input)[:80]})"

def build_action_detail(
    tool_name:    str,
    tool_input:   dict,
    current_state: dict | None = None,
    new_state:     dict | None = None,
) -> str:
    """
    Fuller description including consequences and optionally a diff
    between current and new state.
    """
    lines = [f"Tool: {tool_name}", f"Arguments: {json.dumps(tool_input, indent=2)}"]
    if current_state and new_state:
        old_str = json.dumps(current_state, indent=2)
        new_str = json.dumps(new_state, indent=2)
        diff = list(difflib.unified_diff(
            old_str.splitlines(), new_str.splitlines(),
            fromfile="before", tofile="after", lineterm=""
        ))
        if diff:
            lines.append("Changes:")
            lines.extend(diff[:30])  # cap at 30 lines
    return "\n".join(lines)

def build_recent_context(messages: list[dict], last_n: int = 5) -> list[str]:
    """
    Extract the last N tool calls from the conversation history
    as a list of one-line strings for display in the notification.
    """
    context = []
    for msg in reversed(messages):
        if not isinstance(msg.get("content"), list):
            continue
        for block in msg["content"]:
            if isinstance(block, dict) and block.get("type") == "tool_use":
                name  = block.get("name", "?")
                inp   = json.dumps(block.get("input", {}))[:80]
                context.append(f"{name}({inp})")
                if len(context) >= last_n:
                    return list(reversed(context))
    return list(reversed(context))
